// Copy the repo's generated client helper into this package's src so the
// published @jsonbored/metagraphed always tracks it. Committed at the repo
// root (regenerated by `npm run build`), so this is a pure copy — no network
// or codegen here. The contract TYPES (previously copied here too) instead
// come from the metagraphed-contract workspace package
// (packages/contract/index.d.ts) as a real devDependency -- see
// src/index.ts's `export type * from "metagraphed-contract"` -- so there is
// nothing to copy for those anymore; tsup's --dts bundling inlines them
// directly into this package's own published dist/index.d.ts.
import { promises as fs } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const here = path.dirname(fileURLToPath(import.meta.url));
const packageRoot = path.resolve(here, "..");
const repoRoot = path.resolve(packageRoot, "..", "..");
const srcDir = path.join(packageRoot, "src");

const copies = [["generated/metagraphed-client.ts", "metagraphed-client.ts"]];

await fs.mkdir(srcDir, { recursive: true });
for (const [from, to] of copies) {
  const source = path.join(repoRoot, from);
  const content = await fs.readFile(source, "utf8");
  await fs.writeFile(path.join(srcDir, to), content, "utf8");
}
console.log(
  `Synced ${copies.length} generated file(s) into packages/client/src.`,
);
